import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { usePlayer } from '../context/PlayerContext';
import { useLocation } from 'react-router-dom';
import { FaPlay, FaHeart, FaFire, FaUserPlus, FaEllipsisH, FaRetweet, FaCommentAlt, FaTrash } from 'react-icons/fa';
import { useAuth } from '../context/AuthContext';

const Home = () => {
  const [songs, setSongs] = useState([]);
  const [sidebarData, setSidebarData] = useState({ likedSongs: [], history: [] });
  const [menuOpenId, setMenuOpenId] = useState(null); // State quản lý menu 3 chấm nào đang mở
  const { playSong } = usePlayer();
  const { search } = useLocation();
  const { user, updateUser } = useAuth();

  const topArtists = [
    { name: "Son Tung M-TP", followers: "14.2M", image: "https://yt3.googleusercontent.com/c-Z7mIlntSpG6VyQ5ZqaPggqkZRhaySr-H5ZEazFN2iR1pP4eD1UGekwu0y--c4CSVhJJ1A4QT8=s900-c-k-c0x00ffffff-no-rj" },
    { name: "Den Vau", followers: "5.8M", image: "https://images2.thanhnien.vn/zoom/686_429/528068263637045248/2023/6/5/edit-den-453-16859631579211756268460-97-0-966-1390-crop-16859631696641378413218.png" },
    { name: "HIEUTHUHAI", followers: "3.1M", image: "https://i.scdn.co/image/ab67616d00001e02c006b0181a3846c1c63e178f" },
    { name: "Negav", followers: "2.5M", image: "https://hosongoisao.com/wp-content/uploads/2025/07/logo-negav.jpg" },
  ];

  useEffect(() => {
    const fetchSongs = async () => {
      try {
        const res = await axios.get(`http://localhost:5000/api/songs${search}`);
        setSongs(res.data);
      } catch (err) {
        console.error("Error fetching songs:", err);
      }
    };
    fetchSongs();
  }, [search]);

  // Fetch Sidebar Data (Likes & History)
  useEffect(() => {
    const fetchUserData = async () => {
        if (user) {
            try {
                const res = await axios.get(`http://localhost:5000/api/users/${user._id}`);
                setSidebarData({
                    likedSongs: res.data.likedSongs || [],
                    history: res.data.history || []
                });
            } catch (err) {
                console.error(err);
            }
        }
    };
    fetchUserData();
  }, [user]);

  const handlePlay = async (song) => {
      // Truyền thêm danh sách bài hát hiện tại vào context để Player biết đường next/prev
      playSong(song, songs); 
      try {
          await axios.put(`http://localhost:5000/api/songs/${song._id}/play`);
          
          // 2. Thêm vào lịch sử cá nhân (nếu đã đăng nhập)
          if (user) {
             await axios.put(`http://localhost:5000/api/users/history/${song._id}`, {}, {
                headers: { token: `Bearer ${user.token}` }
             });
             // Cập nhật lại history ngay lập tức trên giao diện
             setSidebarData(prev => ({
                 ...prev,
                 history: [song, ...prev.history.filter(s => s._id !== song._id)].slice(0, 20)
             }));
          }
      } catch (err) {
          console.error(err);
      }
  };

  const handleLike = async (id) => {
      if (!user) return alert("Please login to like songs!");
      try {
          const res = await axios.put(`http://localhost:5000/api/users/like/${id}`, {}, {
             headers: { token: `Bearer ${user.token}` }
          });
          
          // Cập nhật số lượng like trên giao diện
          if (res.data === "Liked") {
              setSongs(songs.map(song => song._id === id ? { ...song, likes: song.likes + 1 } : song));
              // Cập nhật user context để tim chuyển đỏ ngay lập tức
              updateUser({ likedSongs: [...(user.likedSongs || []), id] });
              // Cập nhật sidebar likes
              const likedSong = songs.find(s => s._id === id);
              if(likedSong) {
                  setSidebarData(prev => ({ ...prev, likedSongs: [likedSong, ...prev.likedSongs] }));
              }
          } else {
              setSongs(songs.map(song => song._id === id ? { ...song, likes: song.likes - 1 } : song));
              // Cập nhật user context để tim chuyển nhạt
              updateUser({ likedSongs: (user.likedSongs || []).filter(songId => songId !== id) });
              // Cập nhật sidebar likes
              setSidebarData(prev => ({ ...prev, likedSongs: prev.likedSongs.filter(s => s._id !== id) }));
          }
      } catch (err) {
          console.error(err);
      }
  };

  // Hàm xóa bài hát
  const handleDelete = async (id) => {
      if(!window.confirm("Bạn có chắc chắn muốn xóa bài hát này không? Hành động này không thể hoàn tác.")) return;
      
      try {
          await axios.delete(`http://localhost:5000/api/songs/${id}`, {
              headers: { token: `Bearer ${user.token}` }
          });
          
          // Cập nhật lại danh sách bài hát trên giao diện ngay lập tức
          setSongs(songs.filter(song => song._id !== id));
          setMenuOpenId(null); // Đóng menu
          alert("Đã xóa bài hát thành công!");
      } catch (err) {
          console.error(err);
          alert("Xóa thất bại! Có lỗi xảy ra.");
      }
  };

  // Hàm format số (1200 -> 1.2k)
  const formatNumber = (num) => {
    if (!num) return 0;
    if (num >= 1000000) return (num / 1000000).toFixed(1) + 'M';
    if (num >= 1000) return (num / 1000).toFixed(1) + 'k';
    return num;
  };

  // Component hiển thị bài hát nhỏ ở sidebar (Giống ảnh mẫu)
  const SidebarTrack = ({ song }) => (
      <div className="flex gap-3 mb-4 group cursor-pointer" onClick={() => handlePlay(song)}>
          <div className="relative w-12 h-12 flex-shrink-0">
              <img src={song.coverImage} alt={song.title} className="w-full h-full object-cover rounded-sm" />
              <div className="absolute inset-0 bg-black/20 hidden group-hover:flex items-center justify-center text-white">
                  <FaPlay size={10} />
              </div>
          </div>
          <div className="overflow-hidden min-w-0 flex-1">
              <p className="text-xs text-gray-500 truncate hover:underline">{song.artist}</p>
              <p className="text-sm font-medium text-gray-900 truncate hover:text-black">{song.title}</p>
              
              <div className="flex items-center gap-3 text-[10px] text-gray-400 mt-1">
                  <span className="flex items-center gap-1"><FaPlay size={8} /> {formatNumber(song.plays)}</span>
                  <span className="flex items-center gap-1"><FaHeart size={8} /> {formatNumber(song.likes)}</span>
                  <span className="flex items-center gap-1"><FaRetweet size={8} /> 12</span>
                  <span className="flex items-center gap-1"><FaCommentAlt size={8} /> 5</span>
              </div>
          </div>
      </div>
  );

  return (
    <div className="max-w-7xl mx-auto pt-4 md:pt-8 pb-32 px-4 flex gap-8">
      
      {/* Cột Chính (Danh sách nhạc) */}
      <div className="flex-1">
        <div className="flex flex-col md:flex-row md:items-center gap-2 mb-6 border-b border-[#A5D8FF]/30 pb-4">
            <h2 className="text-xl md:text-2xl font-bold text-gray-700 truncate">
                {/* Thêm decodeURIComponent vào đây để sửa lỗi hiển thị font chữ */}
                {search ? `Search: "${decodeURIComponent(search.split('=')[1])}"` : "Chill Vibes & Lofi"}
            </h2>
            {!search && <FaFire className="text-[#FFB703] text-xl md:text-2xl animate-pulse hidden md:block" />}
        </div>
        
        {/* Responsive Grid: 1 cột (Mobile) -> 2 cột (Tablet) -> 3 cột (Laptop) -> 4 cột (Desktop) */}
        <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4 md:gap-6">
            {songs.map((song) => {
                const isLiked = user?.likedSongs?.includes(song._id);
                // Kiểm tra xem người dùng hiện tại có phải là chủ bài hát không
                // song.uploader lưu ID người đăng
                const isOwner = user && (song.uploader === user._id);

                return (
                <div key={song._id} className="bg-white rounded-xl group hover:shadow-lg hover:shadow-[#A5D8FF]/20 transition-all duration-300 border border-transparent hover:border-[#A5D8FF]/50 overflow-hidden hover:-translate-y-1 flex md:block relative">
                    {/* Ảnh bìa */}
                    <div className="relative aspect-square w-24 md:w-full overflow-hidden cursor-pointer flex-shrink-0" onClick={() => handlePlay(song)}>
                        <img src={song.coverImage} alt={song.title} className="w-full h-full object-cover group-hover:scale-105 transition duration-500" />
                        <div className="absolute inset-0 bg-[#A5D8FF]/20 group-hover:bg-[#A5D8FF]/40 transition flex items-center justify-center opacity-0 group-hover:opacity-100">
                            <button className="w-8 h-8 md:w-14 md:h-14 bg-[#FFB703] rounded-full flex items-center justify-center text-white shadow-lg transform scale-0 group-hover:scale-100 transition duration-300">
                                <FaPlay className="ml-1 text-sm md:text-xl" />
                            </button>
                        </div>
                    </div>

                    {/* Thông tin bài hát */}
                    <div className="p-3 flex-1 flex flex-col justify-center md:block min-w-0">
                        <h3 className="font-bold text-gray-700 truncate text-sm md:text-base hover:text-[#FFB703] cursor-pointer transition">{song.title}</h3>
                        <p className="text-xs md:text-sm text-gray-400 truncate mb-1 md:mb-3">{song.artist}</p>
                        
                        {/* Waveform Giả */}
                        <div className="h-8 w-full bg-[#FAF7F2] rounded mb-3 items-end justify-between px-1 overflow-hidden opacity-70 hidden md:flex">
                            {[...Array(15)].map((_, i) => (
                                <div 
                                    key={i} 
                                    className="w-1.5 bg-[#A5D8FF] rounded-t group-hover:bg-[#FFB703] transition" 
                                    style={{ height: `${20 + Math.random() * 80}%` }}
                                ></div>
                            ))}
                        </div>

                        {/* Stats */}
                        <div className="flex justify-between items-center text-xs text-gray-400 font-medium border-t-0 md:border-t border-gray-100 pt-0 md:pt-2 mt-1 md:mt-0">
                            <span className="flex items-center gap-1">▶ {formatNumber(song.plays)}</span>
                            <div className="flex gap-3 relative">
                                <button 
                                    onClick={(e) => { e.stopPropagation(); handleLike(song._id); }} 
                                    className={`flex items-center gap-1 transition ${isLiked ? 'text-[#FFB703]' : 'hover:text-[#FFB703]'}`}
                                    title="Like"
                                >
                                    <FaHeart /> {formatNumber(song.likes)}
                                </button>
                                
                                {/* Chỉ hiện nút 3 chấm nếu là chủ sở hữu (isOwner = true) */}
                                {isOwner && (
                                    <>
                                        <button 
                                            onClick={(e) => { e.stopPropagation(); setMenuOpenId(menuOpenId === song._id ? null : song._id); }}
                                            className="hover:text-gray-600 hidden md:block p-1 rounded-full hover:bg-gray-100 transition"
                                        >
                                            <FaEllipsisH />
                                        </button>

                                        {/* Menu Dropdown Xóa */}
                                        {menuOpenId === song._id && (
                                            <div className="absolute right-0 bottom-full mb-2 w-32 bg-white shadow-xl rounded-lg border border-gray-100 z-20 overflow-hidden animate-fade-in-up">
                                                <button 
                                                    onClick={(e) => { e.stopPropagation(); handleDelete(song._id); }}
                                                    className="flex items-center gap-2 w-full text-left px-4 py-2 text-xs text-red-500 hover:bg-red-50 font-bold transition"
                                                >
                                                    <FaTrash /> Xóa bài hát
                                                </button>
                                            </div>
                                        )}
                                    </>
                                )}
                            </div>
                        </div>
                    </div>
                </div>
            )})}
        </div>
      </div>

      {/* Cột Phụ (Sidebar) - Chỉ hiện trên màn hình lớn (xl) */}
      <div className="w-80 hidden xl:block sticky top-24 h-fit space-y-8">
            {/* Top Artists */}
            <div className="bg-white p-5 rounded-xl shadow-sm border border-[#A5D8FF]/20">
                <div className="flex justify-between items-center mb-4 border-b border-gray-100 pb-2">
                    <h3 className="font-bold text-gray-600 text-sm uppercase">Artists to Follow</h3>
                    <span className="text-xs text-[#A5D8FF] cursor-pointer hover:text-[#FFB703]">Refresh</span>
                </div>
                <ul className="space-y-4">
                    {topArtists.map((artist, idx) => (
                        <li key={idx} className="flex items-center justify-between group">
                            <div className="flex items-center gap-3">
                                <div className="w-10 h-10 rounded-full bg-[#FAF7F2] overflow-hidden border border-gray-100">
                                    {/* Sử dụng ảnh thật từ mảng topArtists */}
                                    <img src={artist.image} alt="avatar" className="w-full h-full object-cover" />
                                </div>
                                <div>
                                    <p className="text-sm font-bold text-gray-700 group-hover:text-[#FFB703] cursor-pointer truncate w-32">{artist.name}</p>
                                    <p className="text-xs text-gray-400">{artist.followers} followers</p>
                                </div>
                            </div>
                            <button className="text-xs border border-[#A5D8FF] text-[#A5D8FF] px-3 py-1 rounded-full hover:bg-[#A5D8FF] hover:text-white transition flex items-center gap-1">
                                <FaUserPlus /> Follow
                            </button>
                        </li>
                    ))}
                </ul>
            </div>

            {/* LIKES SECTION */}
            <div>
                 <div className="flex justify-between items-center mb-4 text-gray-500 border-b pb-2">
                     <h3 className="text-xs font-bold uppercase text-gray-600">{sidebarData.likedSongs.length} Likes</h3>
                     <span className="text-xs cursor-pointer hover:text-gray-800">View all</span>
                 </div>
                 
                 {sidebarData.likedSongs.length > 0 ? (
                     <div className="flex flex-col">
                         {sidebarData.likedSongs.slice(0, 3).map(song => (
                             <SidebarTrack key={song._id} song={song} />
                         ))}
                     </div>
                 ) : (
                     <p className="text-xs text-gray-400 italic">You haven't liked any tracks yet.</p>
                 )}
            </div>

            {/* HISTORY SECTION */}
            <div>
                 <div className="flex justify-between items-center mb-4 text-gray-500 border-b pb-2">
                     <h3 className="text-xs font-bold uppercase text-gray-600">Listening History</h3>
                     <span className="text-xs cursor-pointer hover:text-gray-800">View all</span>
                 </div>

                 {sidebarData.history.length > 0 ? (
                     <div className="flex flex-col">
                         {sidebarData.history.slice(0, 3).map(song => (
                             <SidebarTrack key={song._id} song={song} />
                         ))}
                     </div>
                 ) : (
                     <p className="text-xs text-gray-400 italic">Start listening to build your history.</p>
                 )}
            </div>

            {/* Footer Links */}
            <div className="text-[11px] text-gray-400 flex flex-wrap gap-x-2 gap-y-1 pt-4 border-t">
                <span className="hover:text-gray-600 cursor-pointer">Legal</span> • 
                <span className="hover:text-gray-600 cursor-pointer">Privacy</span> • 
                <span className="hover:text-gray-600 cursor-pointer">Cookies</span> • 
                <span className="hover:text-gray-600 cursor-pointer">Imprint</span> • 
                <span className="hover:text-gray-600 cursor-pointer">Charts</span>
            </div>
      </div>

    </div>
  );
};

export default Home;
